const AWS = require('aws-sdk');
const { exec } = require('child_process');

exports.handler = async (event) => {
    const s3 = new AWS.S3();
    const bucketName = event.Records[0].s3.bucket.name;
    const key = decodeURIComponent(event.Records[0].s3.object.key.replace(/\+/g, ' '));
    const outputFormat = event.Records[0].eventMetadata.outputFormat;

    if (!outputFormat || !['jpg', 'png', 'gif'].includes(outputFormat.toLowerCase())) {
        throw new Error('Invalid output format');
    }

    const inputParams = {
        Bucket: bucketName,
        Key: key
    };

    try {
        const data = await s3.getObject(inputParams).promise();
        const tempInputPath = `/tmp/${key}`;
        const tempOutputPath = `/tmp/output.${outputFormat}`;

        // Write the image to a temporary file
        require('fs').writeFileSync(tempInputPath, data.Body);

        // Execute ImageMagick convert command
        await new Promise((resolve, reject) => {
            exec(`convert ${tempInputPath} ${tempOutputPath}`, (error, stdout, stderr) => {
                if (error) {
                    console.error(`Error executing ImageMagick: ${stderr}`);
                    return reject(error);
                }
                resolve();
            });
        });

        // Upload the converted image back to S3
        const outputParams = {
            Bucket: bucketName,
            Key: key.replace(/\.\w+$/, `.${outputFormat}`),
            Body: require('fs').readFileSync(tempOutputPath),
            ContentType: `image/${outputFormat}`
        };

        await s3.upload(outputParams).promise();
        console.log(`Image converted and uploaded successfully`);
    } catch (error) {
        console.error(`Error processing image: ${error}`);
        throw error;
    }
};